   242→/* ===== Message history ===== */
   243→function addMessage(text, timestamp, status) {
   244→  // Hide empty state
   245→  messagesEmpty.style.display = 'none';
   246→
   247→  const el = document.createElement('div');
   248→  el.className = `message ${status}`;
   249→
   250→  const timeStr = new Date(timestamp).toLocaleTimeString([], {
   251→    hour: '2-digit',
   252→    minute: '2-digit',
   253→  });
   254→
   255→  const statusLabel = {
   256→    sending:    'Sending…',
   257→    sent:       'Sent',
   258→    error:      'Failed',
   259→    'no-webhook': 'No webhook',
   260→  };
   261→
   262→  el.innerHTML = `
   263→    <p class="message-text">${escapeHtml(text)}</p>
   264→    <div class="message-meta">
   265→      <span class="message-time">${timeStr}</span>
   266→      <span class="message-status">${statusLabel[status] || status}</span>
   267→    </div>
   268→  `;
   269→
   270→  messagesEl.appendChild(el);
   271→  el.scrollIntoView({ behavior: 'smooth', block: 'end' });
   272→  return el;
   273→}
   274→
   275→function updateMessageStatus(el, status) {
   276→  el.className = `message ${status}`;
   277→  const statusEl = el.querySelector('.message-status');
   278→  const labels = {
   279→    sent:         'Sent',
   280→    error:        'Failed',
   281→    'no-webhook': 'No webhook set',
   282→  };
   283→  if (statusEl) statusEl.textContent = labels[status] || status;
   284→}
