   286→function escapeHtml(str) {
   287→  return str
   288→    .replace(/&/g, '&amp;')
   289→    .replace(/</g, '&lt;')
   290→    .replace(/>/g, '&gt;')
   291→    .replace(/"/g, '&quot;')
   292→    .replace(/'/g, '&#39;');
   293→}
