   322→/* ===== Wake Word Detection ===== */
   323→
   324→function isWakePhrase(transcript) {
   325→  return WAKE_PHRASES.some(phrase => transcript.includes(phrase));
   326→}
   327→
   328→function initWakeRecognition() {
   329→  wakeRecognition = new SpeechRecognition();
   330→  wakeRecognition.continuous     = true;
   331→  wakeRecognition.interimResults = true;
   332→  wakeRecognition.lang           = navigator.language || 'en-US';
   333→  wakeRecognition.maxAlternatives = 1;
   334→
   335→  wakeRecognition.onresult = (event) => {
   336→    for (let i = event.resultIndex; i < event.results.length; i++) {
   337→      const transcript = event.results[i][0].transcript.toLowerCase().trim();
   338→      if (isWakePhrase(transcript)) {
   339→        handleWakeWordDetected();
   340→        return;
   341→      }
   342→    }
   343→  };
   344→
   345→  wakeRecognition.onerror = (event) => {
   346→    if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
   347→      // Microphone access denied — silently disable wake mode
   348→      disableWakeMode();
   349→      return;
   350→    }
   351→    if (wakeMode && !isListening && !wakeTriggered) {
   352→      scheduleWakeRestart();
   353→    }
   354→  };
   355→
   356→  wakeRecognition.onend = () => {
   357→    // Chrome stops continuous recognition periodically — restart unless we
   358→    // deliberately stopped it to hand off to main recording.
   359→    if (wakeMode && !isListening && !wakeTriggered) {
   360→      scheduleWakeRestart();
   361→    }
   362→  };
   363→}
   364→
   365→function startWakeRecognition() {
   366→  if (!wakeRecognition) initWakeRecognition();
   367→  wakeTriggered = false;
   368→  micRing.classList.add('listening-passive');
   369→  try {
   370→    wakeRecognition.start();
   371→  } catch (e) {
   372→    // InvalidStateError when already started — reinit and retry
   373→    initWakeRecognition();
   374→    try { wakeRecognition.start(); } catch (_) {}
   375→  }
   376→}
   377→
   378→function stopWakeRecognition() {
   379→  micRing.classList.remove('listening-passive');
   380→  if (wakeRecognition) {
   381→    try { wakeRecognition.stop(); } catch (_) {}
   382→  }
   383→}
   384→
   385→function scheduleWakeRestart() {
   386→  clearTimeout(wakeRestartTimer);
   387→  wakeRestartTimer = setTimeout(() => {
   388→    if (wakeMode && !isListening && !wakeTriggered) {
   389→      startWakeRecognition();
   390→    }
   391→  }, 300);
   392→}
   393→
   394→function handleWakeWordDetected() {
   395→  if (isListening || wakeTriggered) return;
   396→  wakeTriggered = true;
   397→  wakeTriggeredRecording = true; // flag so finishRecording auto-sends
   398→  stopWakeRecognition();
   399→  // Give the recognition engine a moment to fully stop before starting main recording
   400→  setTimeout(() => {
   401→    wakeTriggered = false;
   402→    startListening();
   403→  }, 250);
   404→}
   405→
   406→function enableWakeMode() {
   407→  wakeMode = true;
   408→  wakeBtn.classList.add('wake-active');
   409→  wakeBtn.setAttribute('aria-pressed', 'true');
   410→  wakeBtn.setAttribute('aria-label', 'Disable wake word');
   411→  wakeBtn.title = 'Wake word: ON';
   412→  localStorage.setItem('wakeMode', '1');
   413→  updateWakeHint();
   414→  if (!isListening) startWakeRecognition();
   415→}
   416→
   417→function disableWakeMode() {
   418→  wakeMode = false;
   419→  wakeBtn.classList.remove('wake-active');
   420→  wakeBtn.setAttribute('aria-pressed', 'false');
   421→  wakeBtn.setAttribute('aria-label', 'Enable wake word');
   422→  wakeBtn.title = 'Wake word: Hey Chill';
   423→  localStorage.setItem('wakeMode', '0');
   424→  clearTimeout(wakeRestartTimer);
   425→  stopWakeRecognition();
   426→  updateWakeHint();
   427→}
   428→
   429→function updateWakeHint() {
   430→  if (!isListening) {
   431→    micHint.textContent = wakeMode ? 'Say "Hey Chill" or tap' : 'Tap to speak';
   432→  }
   433→}
   434→
   435→wakeBtn.addEventListener('click', () => {
   436→  if (wakeMode) {
   437→    disableWakeMode();
   438→  } else {
   439→    enableWakeMode();
   440→  }
   441→});
   442→
   443→// Restore wake mode preference across sessions
   444→if (SpeechRecognition && localStorage.getItem('wakeMode') === '1') {
   445→  enableWakeMode();
   446→}
